misc_custom_css.custom_css:
@import url('https://fonts.googleapis.com/css2?family=Geist:wght@400;500;600;700&family=Geist+Mono:wght@400;500&display=swap');


/* ===== builder bridge (Phase 2): map builder output -> source design ===== */
/* Sections use clean pfu-* classes + a css_id; section layout (padding/bg) is mapped to
   those intentional classes here (not incidental source names). Component leaves keep
   well-mapped classes (.method-tile, .trust-pillar, .what-pay-row, .section-sub, …) that
   the carried stylesheet below already styles. */
/* page content uses the brand font (scoped to .entry-content — does NOT touch chrome) */
.entry-content { font-family: var(--font); color: var(--text); }

/* per-section vertical rhythm + backgrounds (ported from the source section rules) */
.pfu-hero        { padding: 40px 0 48px; }
.pfu-match       { padding: 8px 0 80px; }
.pfu-what        { padding: 0 0 88px; }
.pfu-trust       { padding: 0 0 80px; }
.pfu-trust-strip { padding: 24px 0; background: var(--bg-alt); border-block: 1px solid var(--border); }
.pfu-listing     { padding: 0 0 80px; }
.pfu-compare     { padding: 72px 0; background: var(--bg-alt); }
.pfu-methods     { padding: 72px 0; }
.pfu-faq         { padding: 72px 0; background: linear-gradient(180deg, var(--bg-alt) 0%, #F0F4F8 100%); }
.pfu-resources   { padding: 72px 0; }

/* special_heading output -> source heading scale (scoped to builder sections only) */
[class*="pfu-"] .heading-overline { font-size: 13px; font-weight: 500; color: var(--text-muted); letter-spacing: -0.1px; margin-bottom: 16px; text-transform: none; }
[class*="pfu-"] .heading-title { font-size: clamp(28px, 3.5vw, 40px); font-weight: 600; letter-spacing: -1.2px; line-height: 1.1; color: var(--black); margin-bottom: 16px; }
.pfu-hero .heading-title { font-size: clamp(38px, 5vw, 60px); line-height: 1.0; letter-spacing: -2px; }
.pfu-hero .heading-title em { font-style: italic; color: var(--blue); font-weight: 500; }
[class*="pfu-"] .heading-subtitle, [class*="pfu-"] .section-sub { font-size: 17px; color: var(--text-muted); max-width: 720px; line-height: 1.55; letter-spacing: -0.1px; margin-bottom: 8px; }

/* icon_box wrappers inherit the source card / tile / pillar looks via their component classes */
.pfu-trust .trust-pillar, .pfu-resources .trust-block { background: var(--bg); border: 1px solid var(--border); border-radius: 18px; padding: 28px; height: 100%; }
.pfu-methods .method-tile { background: var(--bg); border: 1px solid var(--border); border-radius: 12px; padding: 14px; height: 100%; }
.pfu-what .pfu-what-check { margin-top: 4px; }

.pfu-placeholder { display: block; }

/* ===== chrome bridge (Phase 3): theme header/footer -> source topbar/footer look ===== */
/* Confirmed selectors: #masthead (header), .primary-menu (primary location), #colophon (footer). */
#masthead, #masthead .header-main { background: rgba(255, 255, 255, 0.85); -webkit-backdrop-filter: blur(8px); backdrop-filter: blur(8px); }
#masthead { border-bottom: 1px solid var(--border); }
#masthead .primary-menu { display: flex; gap: 28px; align-items: center; }
#masthead .primary-menu a { font-size: 14px; color: var(--text-muted); font-weight: 500; letter-spacing: -0.1px; transition: color .15s; }
#masthead .primary-menu a:hover { color: var(--text); }
#masthead .site-title, #masthead .site-title a { font-size: 20px; font-weight: 600; letter-spacing: -0.4px; color: var(--text); }
#colophon { font-size: 12px; color: var(--text-light); line-height: 1.7; letter-spacing: -0.1px; }
#colophon a { color: var(--text-muted); font-weight: 500; }
#colophon a:hover { color: var(--text); }


/* ===== carried source stylesheet (payforit-global.css) ===== */

:root{
  --blue: #185FA5;
  --blue-light: #4A8BCC;
  --blue-bg: #F0F6FC;
  --amber: #EF9F27;
  --green: #1FBA8E;
  --green-dark: #15A179;
  --green-bg: #E1F5EE;
  --green-text: #0F6E56;
  --red-text: #A32D2D;

  --black: #0A0A0F;
  --text: #14141A;
  --text-muted: #5A5A65;
  --text-light: #8E8E97;
  --text-faint: #B8B8BE;
  --bg: #FFFFFF;
  --bg-alt: #FAFAF7;
  --border: rgba(10, 10, 15, 0.07);
  --border-strong: rgba(10, 10, 15, 0.12);

  --dark: #0F0F1A;

  --font: 'Geist', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-mono: 'Geist Mono', ui-monospace, 'SF Mono', Menlo, monospace;
}
.entry-content .topbar{
  padding: 22px 0;
  border-bottom: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.85);
  backdrop-filter: blur(8px);
  position: sticky; top: 0; z-index: 100;
}
.entry-content .topbar-inner{ display: flex; align-items: center; justify-content: space-between; }
.entry-content .brand{ display: flex; align-items: center; gap: 11px; }
.entry-content .brand-mark{
  width: 28px; height: 36px;
  background: var(--blue);
  border-radius: 6px;
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  color: white; font-weight: 600;
  position: relative;
}
.entry-content .brand-mark::after{
  content: ''; position: absolute; bottom: 5px;
  width: 11px; height: 1.6px; background: white; border-radius: 1px;
}
.entry-content .brand-mark span{ font-size: 17px; line-height: 1; padding-bottom: 5px; }
.entry-content .wordmark{ font-size: 20px; font-weight: 600; letter-spacing: -0.4px; }
.entry-content .wordmark .blue-part{ color: var(--blue); }
.entry-content .nav{ display: flex; gap: 28px; }
.entry-content .nav a{
  font-size: 14px; color: var(--text-muted); font-weight: 500;
  transition: color 0.15s; letter-spacing: -0.1px;
}
.entry-content .nav a:hover{ color: var(--text); }
.entry-content .hero{
  padding: 40px 0 48px;
}
.entry-content .hero-grid{
  display: grid;
  grid-template-columns: 1.1fr 0.9fr;
  gap: 60px;
  align-items: center;
}
.entry-content .eyebrow{
  display: inline-flex; align-items: center; gap: 8px;
  font-size: 13px; font-weight: 500;
  color: var(--blue); letter-spacing: -0.1px;
  margin-bottom: 28px;
  padding: 6px 14px;
  background: var(--blue-bg);
  border-radius: 999px;
}
.entry-content .eyebrow-dot{ width: 5px; height: 5px; background: var(--blue); border-radius: 50%; }
.entry-content .h1{
  font-size: clamp(38px, 5vw, 60px);
  line-height: 1.0; font-weight: 600;
  letter-spacing: -2px;
  color: var(--black);
  margin-bottom: 16px;
}
.entry-content .h1 em{ font-style: italic; color: var(--blue); font-weight: 500; }
.entry-content .hero-sub{
  font-size: 18px; color: var(--text-muted);
  line-height: 1.5; margin-bottom: 22px;
  max-width: 520px; letter-spacing: -0.2px;
}
.entry-content .tested-by{
  display: inline-flex; align-items: center; gap: 12px;
  padding: 8px 16px 8px 10px;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 999px;
  font-size: 13px; color: var(--text-muted);
}
.entry-content .tested-avatars{ display: flex; align-items: center; }
.entry-content .tested-avatar{
  width: 26px; height: 26px;
  border-radius: 50%;
  border: 2px solid var(--bg);
  margin-left: -8px;
  display: flex; align-items: center; justify-content: center;
  font-weight: 600; font-size: 10px;
  color: white;
  letter-spacing: -0.2px;
}
.entry-content .tested-avatar:first-child{ margin-left: 0; }
.entry-content .tested-avatar.a1{ background: linear-gradient(135deg, var(--blue), var(--blue-light)); }
.entry-content .tested-avatar.a2{ background: linear-gradient(135deg, #1FBA8E, #16A074); }
.entry-content .tested-avatar.a3{ background: linear-gradient(135deg, #EF9F27, #D67F0A); }
.entry-content .tested-by strong{ color: var(--text); font-weight: 600; }
.entry-content .hero-visual{
  display: flex; justify-content: center; align-items: center;
  position: relative;
}
.entry-content .phone{
  width: 260px;
  height: 520px;
  background: linear-gradient(145deg, #1F1F2A 0%, #0A0A12 100%);
  border-radius: 36px;
  padding: 10px;
  box-shadow:
    0 1px 2px rgba(0,0,0,0.1),
    0 24px 60px -16px rgba(24, 95, 165, 0.3),
    0 50px 100px -24px rgba(0,0,0,0.18);
  position: relative;
  transform: rotate(-3deg);
  transition: transform 0.6s cubic-bezier(0.2, 0.8, 0.2, 1);
}
.entry-content .phone:hover{ transform: rotate(0deg) translateY(-4px); }
.entry-content .phone-screen{
  width: 100%; height: 100%;
  background: linear-gradient(180deg, #FAFAF7 0%, #F0F4F8 100%);
  border-radius: 26px;
  overflow: hidden;
  position: relative;
  display: flex; flex-direction: column;
}
.entry-content .phone-notch{
  position: absolute; top: 8px; left: 50%;
  transform: translateX(-50%);
  width: 84px; height: 24px;
  background: #0A0A12;
  border-radius: 999px;
  z-index: 2;
}
.entry-content .phone-statusbar{
  display: flex; justify-content: space-between; align-items: center;
  padding: 14px 24px 8px;
  font-size: 12px; font-weight: 600;
  color: var(--black);
  font-feature-settings: 'tnum';
}
.entry-content .phone-statusbar-icons{ display: flex; gap: 5px; align-items: center; }
.entry-content .phone-statusbar-icons svg{ width: 12px; height: 9px; opacity: 0.85; }
.entry-content .phone-content{
  padding: 32px 20px 20px;
  flex: 1;
  display: flex; flex-direction: column;
}
.entry-content .phone-app-header{
  display: flex; justify-content: space-between; align-items: center;
  margin-bottom: 22px;
}
.entry-content .phone-app-name{
  font-size: 12px; font-weight: 600;
  color: var(--text-muted);
  letter-spacing: -0.1px;
}
.entry-content .phone-close{ font-size: 16px; color: var(--text-light); font-weight: 400; }
.entry-content .phone-success{
  display: flex; flex-direction: column; align-items: center;
  text-align: center;
}
.entry-content .phone-check{
  width: 56px; height: 56px;
  background: linear-gradient(135deg, #1FBA8E, #16A074);
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  margin-bottom: 18px;
  box-shadow: 0 6px 20px rgba(31, 186, 142, 0.35);
}
.entry-content .phone-check svg{ width: 28px; height: 28px; color: white; }
.entry-content .phone-confirm-text{
  font-size: 15px; font-weight: 600;
  color: var(--black); margin-bottom: 6px;
  letter-spacing: -0.3px;
}
.entry-content .phone-confirm-sub{
  font-size: 12px; color: var(--text-muted);
  margin-bottom: 22px; line-height: 1.4;
}
.entry-content .phone-receipt{
  background: white;
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 14px;
  width: 100%;
  text-align: left;
  font-feature-settings: 'tnum';
}
.entry-content .phone-receipt-row{
  display: flex; justify-content: space-between; align-items: center;
  padding: 4px 0;
  font-size: 11px;
}
.entry-content .phone-receipt-label{ color: var(--text-light); }
.entry-content .phone-receipt-value{ color: var(--black); font-weight: 500; }
.entry-content .phone-receipt-amount{ font-size: 20px; font-weight: 700; letter-spacing: -0.5px; color: var(--black); }
.entry-content .phone-receipt-divider{
  height: 1px; background: var(--border);
  margin: 6px 0;
}
.entry-content .float-shape{
  position: absolute;
  border-radius: 14px;
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 500;
  padding: 8px 12px;
  background: white;
  border: 1px solid var(--border);
  box-shadow: 0 8px 24px rgba(0,0,0,0.06);
  display: flex; align-items: center; gap: 8px;
  z-index: 2;
}
.entry-content .float-shape-1{
  top: 18%; left: -4%;
  color: var(--blue);
  animation: float-a 6s ease-in-out infinite;
}
.entry-content .float-shape-2{
  bottom: 16%; right: -2%;
  color: var(--text);
  animation: float-b 7s ease-in-out infinite;
}
@keyframes float-a{
  0%, 100% { transform: translateY(0) rotate(-2deg); }
  50% { transform: translateY(-10px) rotate(-2deg); }
}
@keyframes float-b{
  0%, 100% { transform: translateY(0) rotate(3deg); }
  50% { transform: translateY(-8px) rotate(3deg); }
}
.entry-content .float-dot{
  width: 5px; height: 5px;
  background: currentColor;
  border-radius: 50%;
}
.entry-content .match-section{
  padding: 8px 0 80px;
  display: flex; justify-content: center;
}
.entry-content .match-intro{
  text-align: center;
  max-width: 580px;
  margin: 0 auto 24px;
}
.entry-content .match-intro-eyebrow{
  display: inline-flex; align-items: center; gap: 8px;
  font-size: 11px; font-weight: 600;
  color: var(--green-dark);
  letter-spacing: 1.5px;
  text-transform: uppercase;
  background: var(--green-bg);
  padding: 6px 12px;
  border-radius: 999px;
  margin-bottom: 14px;
}
.entry-content .match-intro-eyebrow-dot{
  width: 6px; height: 6px; background: var(--green); border-radius: 50%;
  position: relative;
}
.entry-content .match-intro-eyebrow-dot::after{
  content: ''; position: absolute; inset: -3px;
  border-radius: 50%;
  background: rgba(31, 186, 142, 0.3);
  animation: pulse 2s ease-out infinite;
}
@keyframes pulse{
  0% { transform: scale(0.8); opacity: 1; }
  100% { transform: scale(2); opacity: 0; }
}
.entry-content .match-intro-text{
  font-size: 16px;
  color: var(--text-muted);
  line-height: 1.55;
  letter-spacing: -0.15px;
}
.entry-content .match-intro-text strong{ color: var(--text); font-weight: 600; }
.entry-content .match-card{
  width: 100%;
  max-width: 760px;
  background: linear-gradient(180deg, #FFFFFF 0%, #FAFCFF 100%);
  border: 1px solid var(--border);
  border-radius: 24px;
  padding: 0;
  box-shadow:
    0 1px 2px rgba(0,0,0,0.02),
    0 4px 16px rgba(0,0,0,0.04),
    0 24px 60px rgba(24, 95, 165, 0.08);
  position: relative;
  overflow: hidden;
}
.entry-content .match-card::before{
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 4px;
  background: linear-gradient(90deg, var(--blue), var(--green) 60%, var(--amber));
}
.entry-content .match-header{
  padding: 28px 32px 0;
  display: flex; justify-content: space-between; align-items: center;
  gap: 16px;
}
.entry-content .match-title-group{}
.entry-content .match-title{
  font-size: 22px; font-weight: 600;
  letter-spacing: -0.6px; margin-bottom: 4px;
  color: var(--black);
  display: flex; align-items: center; gap: 10px;
}
.entry-content .match-title-icon{
  width: 28px; height: 28px;
  background: linear-gradient(135deg, var(--blue), var(--blue-light));
  border-radius: 8px;
  display: flex; align-items: center; justify-content: center;
  color: white;
  flex-shrink: 0;
  box-shadow: 0 2px 6px rgba(24, 95, 165, 0.25);
}
.entry-content .match-title-icon svg{ width: 14px; height: 14px; }
.entry-content .match-sub{
  font-size: 13px; color: var(--text-muted);
  letter-spacing: -0.1px;
  padding-left: 38px;
}
.entry-content .match-progress{
  display: flex; gap: 4px;
  align-items: center;
}
.entry-content .match-progress-dot{
  width: 8px; height: 8px;
  border-radius: 50%;
  background: var(--bg-alt);
  border: 1.5px solid var(--border-strong);
  transition: background 0.2s, border-color 0.2s;
}
.entry-content .match-progress-dot.is-done{
  background: var(--green);
  border-color: var(--green);
}
.entry-content .match-questions{
  padding: 24px 32px;
  display: grid; gap: 20px;
}
.entry-content .match-q-row{
  padding-bottom: 20px;
  border-bottom: 1px solid var(--border);
}
.entry-content .match-q-row:last-child{ border-bottom: none; padding-bottom: 0; }
.entry-content .match-q-label{
  display: flex; align-items: center; gap: 12px;
  margin-bottom: 12px;
}
.entry-content .match-q-num{
  width: 26px; height: 26px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--blue), var(--blue-light));
  color: white;
  display: flex; align-items: center; justify-content: center;
  font-size: 12px; font-weight: 700;
  flex-shrink: 0;
  box-shadow: 0 2px 4px rgba(24, 95, 165, 0.2);
}
.entry-content .match-q-text{
  font-size: 15px; font-weight: 600;
  color: var(--text); letter-spacing: -0.2px;
}
.entry-content .match-options{ display: flex; gap: 8px; flex-wrap: wrap; padding-left: 38px; }
.entry-content .match-option{
  padding: 9px 14px;
  background: var(--bg);
  border: 1px solid var(--border-strong);
  border-radius: 10px;
  font-size: 13px; font-weight: 500;
  color: var(--text-muted);
  cursor: pointer;
  transition: all 0.15s;
  letter-spacing: -0.1px;
}
.entry-content .match-option:hover{
  border-color: var(--blue);
  color: var(--text);
  background: var(--blue-bg);
}
.entry-content .match-option.is-selected{
  background: var(--black); color: white; border-color: var(--black);
  box-shadow: 0 2px 6px rgba(10, 10, 15, 0.15);
}
.entry-content .match-option.is-selected::before{
  content: '✓'; margin-right: 5px; font-weight: 600;
}
.entry-content .match-footer{
  padding: 22px 32px 28px;
  background: linear-gradient(180deg, transparent 0%, rgba(31, 186, 142, 0.03) 100%);
  border-top: 1px solid var(--border);
  display: flex; justify-content: space-between; align-items: center;
  flex-wrap: wrap; gap: 12px;
}
.entry-content .match-cta{
  background: linear-gradient(135deg, var(--green) 0%, var(--green-dark) 100%);
  color: white;
  border: none;
  padding: 14px 26px;
  border-radius: 12px;
  font-family: inherit;
  font-size: 15px; font-weight: 600;
  letter-spacing: -0.2px; cursor: pointer;
  transition: all 0.15s;
  display: inline-flex; align-items: center; gap: 10px;
  box-shadow:
    0 1px 2px rgba(0,0,0,0.05),
    0 4px 12px rgba(31, 186, 142, 0.3);
}
.entry-content .match-cta:hover{
  transform: translateY(-1px);
  box-shadow:
    0 1px 2px rgba(0,0,0,0.05),
    0 8px 20px rgba(31, 186, 142, 0.4);
}
.entry-content .match-cta:active{ transform: translateY(0); }
.entry-content .match-cta svg{ width: 16px; height: 16px; }
.entry-content .match-help{
  font-size: 12px; color: var(--text-light);
  letter-spacing: -0.1px;
  display: inline-flex; align-items: center; gap: 6px;
}
.entry-content .match-help svg{ width: 12px; height: 12px; opacity: 0.7; }
.entry-content .section-eyebrow{
  font-size: 13px; font-weight: 500;
  color: var(--text-muted); letter-spacing: -0.1px;
  margin-bottom: 16px;
  display: inline-flex; align-items: center; gap: 10px;
}
.entry-content .section-eyebrow::before{
  content: ''; width: 24px; height: 1px; background: var(--text-faint);
}
.entry-content .section-h{
  font-size: clamp(28px, 3.5vw, 40px);
  font-weight: 600; letter-spacing: -1.2px;
  line-height: 1.1; color: var(--black);
  margin-bottom: 16px; max-width: 820px;
}
.entry-content .section-sub{
  font-size: 17px; color: var(--text-muted);
  max-width: 720px; line-height: 1.55;
  letter-spacing: -0.1px; margin-bottom: 40px;
}
.entry-content .what-section{ padding: 0 0 88px; }
.entry-content .what-grid{
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 56px;
  align-items: center;
}
.entry-content .what-checks{
  display: flex; flex-direction: column; gap: 18px;
  margin-top: 28px;
}
.entry-content .what-check{ display: flex; align-items: flex-start; gap: 14px; }
.entry-content .what-check-icon{
  width: 28px; height: 28px;
  background: var(--green-bg);
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  color: var(--green-text);
  flex-shrink: 0;
}
.entry-content .what-check-icon svg{ width: 14px; height: 14px; }
.entry-content .what-check-text{
  font-size: 15px; line-height: 1.5;
  color: var(--text);
  letter-spacing: -0.15px;
}
.entry-content .what-check-text strong{ font-weight: 600; color: var(--black); }
.entry-content .what-visual{
  background: linear-gradient(135deg, #FAFAF7 0%, #F0F6FC 100%);
  border: 1px solid var(--border);
  border-radius: 22px;
  padding: 32px;
  position: relative;
  overflow: hidden;
}
.entry-content .what-visual-caption{
  margin-bottom: 18px;
  padding-bottom: 16px;
  border-bottom: 1px solid var(--border);
}
.entry-content .what-visual-eyebrow{
  display: inline-flex; align-items: center; gap: 6px;
  font-size: 11px; font-weight: 600;
  color: var(--blue);
  letter-spacing: 0.8px;
  text-transform: uppercase;
  margin-bottom: 8px;
}
.entry-content .what-visual-eyebrow-dot{
  width: 5px; height: 5px;
  background: var(--blue);
  border-radius: 50%;
}
.entry-content .what-visual-h{
  font-size: 17px;
  font-weight: 600;
  letter-spacing: -0.3px;
  color: var(--black);
  margin-bottom: 4px;
  line-height: 1.3;
}
.entry-content .what-visual-sub{
  font-size: 13px;
  color: var(--text-muted);
  line-height: 1.45;
